async function seed() {
  try {
    await mongoose.connect(process.env.MONGO_URI || 'mongodb://localhost:27017/placeprep');
    console.log('Connected to MongoDB');

    await AptitudeQuestion.deleteMany({});
    console.log('Cleared existing aptitude questions');

    const inserted = await AptitudeQuestion.insertMany(questions);
    console.log(`Seeded ${inserted.length} aptitude questions`);

    // Summary
    const mockCounts = {};
    questions.forEach(q => {
      mockCounts[q.mockId] = (mockCounts[q.mockId] || 0) + 1;
    });
    console.log('\nMock distribution:');
    Object.entries(mockCounts).forEach(([mockId, count]) => {
      console.log(`  ${mockId}: ${count} questions`);
    });

    await mongoose.disconnect();
    console.log('\nDone! Disconnected from MongoDB');
  } catch (err) {
    console.error('Seed error:', err);
    process.exit(1);
  }
}

seed();
